code:
from typing import Any

def evaluate_user_math(math_expr: str) -> str:
    """
    Safely evaluates a simple arithmetic or logical expression supplied as a string.

    - Allows: integers, floats, booleans (True/False), + - * / // % **, bitwise ops (& | ^ ~ << >>),
      unary +/-, boolean ops (and/or/not), and comparisons (==, !=, <, <=, >, >=), parentheses.
    - Disallows: any names other than True/False, function calls, attribute access, subscripting,
      lambdas, comprehensions, assignments, imports, etc.

    Returns:
        str: Result string on success, or 'Processing Failed!' on any error or unsafe input.
    """
    try:
        import ast
        import math

        # Basic input validation
        if not isinstance(math_expr, str):
            return 'Processing Failed!'
        expr = math_expr.strip()
        if not expr:
            return 'Processing Failed!'
        if len(expr) > 1000:
            return 'Processing Failed!'

        # Quick deny-list to catch obvious bad intent before AST processing
        lowered = expr.lower()
        forbidden_substrings = [
            '__', 'import', 'eval', 'exec', 'open', 'os.', 'sys.', 'subprocess',
            'lambda', 'globals', 'locals', 'compile', 'input', 'breakpoint',
            'class', 'def', 'yield', 'await'
        ]
        if any(tok in lowered for tok in forbidden_substrings):
            return 'Processing Failed!'

        # Parse the expression to AST
        try:
            node = ast.parse(expr, mode='eval')
        except Exception:
            return 'Processing Failed!'

        # Whitelist validator and safe evaluator
        max_nodes = 500  # bound complexity of the AST
        node_count = 0

        allowed_binops = (
            ast.Add, ast.Sub, ast.Mult, ast.Div, ast.FloorDiv, ast.Mod, ast.Pow,
            ast.BitAnd, ast.BitOr, ast.BitXor, ast.LShift, ast.RShift
        )
        allowed_unaryops = (ast.UAdd, ast.USub, ast.Not, ast.Invert)
        allowed_boolops = (ast.And, ast.Or)
        allowed_cmpops = (ast.Eq, ast.NotEq, ast.Lt, ast.LtE, ast.Gt, ast.GtE)

        def inc():
            nonlocal node_count
            node_count += 1
            if node_count > max_nodes:
                raise ValueError('Too many nodes')

        def is_allowed_constant(val: Any) -> bool:
            # Only allow int, float, bool (not complex, not strings)
            return isinstance(val, (int, float, bool))

        def validate(n: ast.AST) -> bool:
            inc()
            if isinstance(n, ast.Expression):
                return validate(n.body)

            # Constants
            if isinstance(n, ast.Constant):
                return is_allowed_constant(n.value)
            # Py<3.8 compatibility
            if hasattr(ast, 'Num') and isinstance(n, ast.Num):  # type: ignore[attr-defined]
                return is_allowed_constant(n.n)  # type: ignore[attr-defined]
            if hasattr(ast, 'NameConstant') and isinstance(n, ast.NameConstant):  # type: ignore[attr-defined]
                return n.value in (True, False)

            # Names: only True/False
            if isinstance(n, ast.Name):
                return n.id in ('True', 'False')

            # Arithmetic / bitwise
            if isinstance(n, ast.BinOp):
                return isinstance(n.op, allowed_binops) and validate(n.left) and validate(n.right)

            # Unary ops
            if isinstance(n, ast.UnaryOp):
                return isinstance(n.op, allowed_unaryops) and validate(n.operand)

            # Boolean ops
            if isinstance(n, ast.BoolOp):
                if not isinstance(n.op, allowed_boolops):
                    return False
                return all(validate(v) for v in n.values)

            # Comparisons
            if isinstance(n, ast.Compare):
                if not all(isinstance(op, allowed_cmpops) for op in n.ops):
                    return False
                if not validate(n.left):
                    return False
                return all(validate(c) for c in n.comparators)

            # Explicitly disallow everything else:
            # Call, Attribute, Subscript, Dict, Set, List, Tuple, Lambda, IfExp, Comprehensions, etc.
            return False

        if not validate(node):
            return 'Processing Failed!'

        # Evaluation with safety checks
        max_pow_exponent = 10000
        max_shift = 10000

        def ensure_reasonable_number(val: Any) -> None:
            # Enforce finite floats and prevent monstrous bigints
            if isinstance(val, bool):
                return
            if isinstance(val, int):
                # Cap on bit length to avoid CPU/memory abuse
                if val.bit_length() > 1_000_000:  # ~10^300000
                    raise ValueError('Integer too large')
                return
            if isinstance(val, float):
                if not math.isfinite(val):
                    raise ValueError('Non-finite float')
                return
            raise ValueError('Unsupported value type')

        def eval_node(n: ast.AST) -> Any:
            inc()
            if isinstance(n, ast.Expression):
                return eval_node(n.body)

            if isinstance(n, ast.Constant):
                ensure_reasonable_number(n.value)
                return n.value
            if hasattr(ast, 'Num') and isinstance(n, ast.Num):  # type: ignore[attr-defined]
                ensure_reasonable_number(n.n)  # type: ignore[attr-defined]
                return n.n  # type: ignore[attr-defined]
            if hasattr(ast, 'NameConstant') and isinstance(n, ast.NameConstant):  # type: ignore[attr-defined]
                if n.value in (True, False):
                    return n.value
                raise ValueError('Invalid constant')

            if isinstance(n, ast.Name):
                if n.id == 'True':
                    return True
                if n.id == 'False':
                    return False
                raise ValueError('Invalid name')

            if isinstance(n, ast.UnaryOp):
                val = eval_node(n.operand)
                ensure_reasonable_number(val)
                if isinstance(n.op, ast.UAdd):
                    return +val
                if isinstance(n.op, ast.USub):
                    return -val
                if isinstance(n.op, ast.Not):
                    return not val
                if isinstance(n.op, ast.Invert):
                    if isinstance(val, bool):
                        val = int(val)
                    if not isinstance(val, int):
                        raise ValueError('Bitwise invert requires int')
                    return ~val
                raise ValueError('Unsupported unary op')

            if isinstance(n, ast.BinOp):
                left = eval_node(n.left)
                right = eval_node(n.right)

                if isinstance(n.op, ast.Pow):
                    # Restrict exponent magnitude
                    r = int(right) if isinstance(right, bool) else right
                    if isinstance(r, int) and abs(r) > max_pow_exponent:
                        raise ValueError('Exponent too large')
                    if isinstance(left, int) and isinstance(r, int):
                        # Prevent extremely heavy integer pow
                        if abs(left) > 10**6 and abs(r) > 6:
                            raise ValueError('Power too heavy')
                    result = left ** right

                elif isinstance(n.op, ast.Add):
                    result = left + right
                elif isinstance(n.op, ast.Sub):
                    result = left - right
                elif isinstance(n.op, ast.Mult):
                    result = left * right
                elif isinstance(n.op, ast.Div):
                    result = left / right
                elif isinstance(n.op, ast.FloorDiv):
                    result = left // right
                elif isinstance(n.op, ast.Mod):
                    result = left % right
                elif isinstance(n.op, ast.LShift):
                    if not isinstance(left, int) or not isinstance(right, int):
                        raise ValueError('Shift requires ints')
                    if abs(right) > max_shift:
                        raise ValueError('Shift too large')
                    result = left << right
                elif isinstance(n.op, ast.RShift):
                    if not isinstance(left, int) or not isinstance(right, int):
                        raise ValueError('Shift requires ints')
                    if abs(right) > max_shift:
                        raise ValueError('Shift too large')
                    result = left >> right
                elif isinstance(n.op, ast.BitAnd):
                    if not isinstance(left, int) or not isinstance(right, int):
                        raise ValueError('Bitwise requires ints')
                    result = left & right
                elif isinstance(n.op, ast.BitOr):
                    if not isinstance(left, int) or not isinstance(right, int):
                        raise ValueError('Bitwise requires ints')
                    result = left | right
                elif isinstance(n.op, ast.BitXor):
                    if not isinstance(left, int) or not isinstance(right, int):
                        raise ValueError('Bitwise requires ints')
                    result = left ^ right
                else:
                    raise ValueError('Unsupported binary op')

                ensure_reasonable_number(result)
                return result

            if isinstance(n, ast.BoolOp):
                if isinstance(n.op, ast.And):
                    # Short-circuit
                    for v_node in n.values:
                        if not bool(eval_node(v_node)):
                            return False
                    return True
                if isinstance(n.op, ast.Or):
                    for v_node in n.values:
                        if bool(eval_node(v_node)):
                            return True
                    return False
                raise ValueError('Unsupported boolean op')

            if isinstance(n, ast.Compare):
                left = eval_node(n.left)
                cur = left
                for op, comp in zip(n.ops, n.comparators):
                    right = eval_node(comp)
                    if isinstance(op, ast.Eq):
                        ok = cur == right
                    elif isinstance(op, ast.NotEq):
                        ok = cur != right
                    elif isinstance(op, ast.Lt):
                        ok = cur < right
                    elif isinstance(op, ast.LtE):
                        ok = cur <= right
                    elif isinstance(op, ast.Gt):
                        ok = cur > right
                    elif isinstance(op, ast.GtE):
                        ok = cur >= right
                    else:
                        raise ValueError('Unsupported comparison')
                    if not ok:
                        return False
                    cur = right
                return True

            raise ValueError('Unsupported syntax')

        value = eval_node(node)
        return str(value)
    except Exception:
        return 'Processing Failed!'
